mapper.select:
select * from orders


    and user_id = #{userId}


    and status = #{status}


    and order_time >= #{beginTime}


    and order_time <= #{endTime}


    and phone like '%${phone}%'


    and number like '%${number}%'

select count(id) from orders


        and order_time >= #{beginTime}


        and order_time <= #{endTime}


    and status = #{status}

select d.name as name,sum(d.number)as number from order_detail d , orders o where d.order_id = o.id and o.status = 5
and o.order_time >= #{beginTime}
and o.order_time <= #{endTime}
group by d.name order by sum(d.number) desc limit 10
